// OKRs with current progress as percentages (0–100)
// Each KR has: target, current, and unit
const okrs = [
  {
    id: 'O1',
    objective: 'Unblock enterprise sales with a complete security foundation',
    quarter: 'Q3 2026',
    key_results: [
      { id: 'O1-KR1', title: 'RBAC shipped by August 15', type: 'binary', target: 1, current: 0, unit: 'shipped' },
      { id: 'O1-KR2', title: 'Audit log shipped by August 29', type: 'binary', target: 1, current: 0, unit: 'shipped' },
      { id: 'O1-KR3', title: 'P0 security incidents in Q3', type: 'binary_inverse', target: 0, current: 0, unit: 'incidents' },
      { id: 'O1-KR4', title: 'New enterprise logos citing security features', type: 'numeric', target: 3, current: 1, unit: 'logos' }
    ]
  },
  {
    id: 'O2',
    objective: 'Establish mobile as a core product surface',
    quarter: 'Q3 2026',
    key_results: [
      { id: 'O2-KR1', title: 'iOS app reaches GA by July 31', type: 'binary', target: 1, current: 0, unit: 'shipped' },
      { id: 'O2-KR2', title: 'Android v1 shipped to 10 beta customers by September 15', type: 'binary', target: 1, current: 0, unit: 'shipped' },
      { id: 'O2-KR3', title: 'Mobile daily active rate ≥ 40%', type: 'numeric', target: 40, current: 43, unit: 'pct' }
    ]
  },
  {
    id: 'O3',
    objective: 'Grow net new ARR by $220k in Q3',
    quarter: 'Q3 2026',
    key_results: [
      { id: 'O3-KR1', title: 'Net new ARR ($k)', type: 'numeric', target: 220, current: 64, unit: 'k USD' },
      { id: 'O3-KR2', title: 'Churn maintained at ≤ 2.1%', type: 'numeric_inverse', target: 2.1, current: 1.9, unit: 'pct' },
      { id: 'O3-KR3', title: 'NPS ≥ 44', type: 'numeric', target: 44, current: 43, unit: 'points' }
    ]
  }
];
return [{ json: { okrs, quarter: 'Q3 2026', week: 'week 2 of 13', as_of: new Date().toISOString().split('T')[0] } }];

const { okrs, quarter, week, as_of } = $input.first().json;
// Compute progress per KR and per Objective
const scored = okrs.map(o => {
  const krs = o.key_results.map(kr => {
    let progress = 0;
    if (kr.type === 'binary') progress = kr.current >= kr.target ? 100 : 0;
    else if (kr.type === 'binary_inverse') progress = kr.current <= kr.target ? 100 : 0;
    else if (kr.type === 'numeric') progress = kr.target > 0 ? Math.min(100, Math.round((kr.current / kr.target) * 100)) : 100;
    else if (kr.type === 'numeric_inverse') progress = kr.target > 0 ? Math.min(100, Math.round(((2 * kr.target - kr.current) / kr.target) * 100)) : 100;
    const status = progress >= 70 ? 'on-track' : progress >= 40 ? 'at-risk' : 'off-track';
    return { ...kr, progress_pct: progress, status };
  });
  const obj_progress = Math.round(krs.reduce((sum, kr) => sum + kr.progress_pct, 0) / krs.length);
  const obj_status = obj_progress >= 70 ? 'on-track' : obj_progress >= 40 ? 'at-risk' : 'off-track';
  return { ...o, key_results: krs, objective_progress_pct: obj_progress, objective_status: obj_status };
});
const overall_pct = Math.round(scored.reduce((sum, o) => sum + o.objective_progress_pct, 0) / scored.length);
return [{ json: { scored, overall_pct, quarter, week, as_of } }];

const { scored, overall_pct, quarter, week, as_of } = $input.first().json;
const emoji = (s) => s === 'on-track' ? '✅' : s === 'at-risk' ? '⚠️' : '❌';
const lines = [
  `OKR PROGRESS TRACKER — ${quarter} | ${week} | As of ${as_of}`,
  `Overall portfolio: ${overall_pct}%`,
  ``
];
for (const o of scored) {
  lines.push(`${emoji(o.objective_status)} ${o.objective} — ${o.objective_progress_pct}% [${o.objective_status}]`);
  for (const kr of o.key_results) {
    lines.push(`    ${emoji(kr.status)} ${kr.title}: ${kr.current} / ${kr.target} ${kr.unit} (${kr.progress_pct}%) [${kr.status}]`);
  }
  lines.push('');
}
const atRisk = scored.flatMap(o => o.key_results.filter(kr => kr.status !== 'on-track').map(kr => ({ objective: o.objective, kr_title: kr.title, progress_pct: kr.progress_pct, status: kr.status })));
if (atRisk.length > 0) {
  lines.push('AT-RISK / OFF-TRACK KEY RESULTS:');
  for (const a of atRisk) lines.push(`  ${emoji(a.status)} [${a.status.toUpperCase()}] ${a.kr_title} (${a.progress_pct}%) under "${a.objective}"`);
}
return [{ json: { scored, overall_pct, quarter, week, as_of, report_text: lines.join('\n') } }];
